mapper.select:
SELECT DISTINCT JSON_KEYS(JSON_EXTRACT(ANNOTATION_JSON, '$.mut')) AS innerKey
FROM mutation
WHERE JSON_EXTRACT(ANNOTATION_JSON, '$.mut') IS NOT NULL;

SELECT JSON_UNQUOTE(JSON_EXTRACT(ANNOTATION_JSON, '$.mut.Actionable')) AS Actionable, COUNT(*) AS count
FROM mutation
GROUP BY JSON_UNQUOTE(JSON_EXTRACT(ANNOTATION_JSON, '$.mut.Actionable'));  

SELECT
#{entrezGeneId} AS "entrezGeneId",
#{proteinPosStart} AS "proteinPosStart",
#{proteinPosEnd} AS "proteinPosEnd",
COUNT(*) AS "count"
FROM mutation
INNER JOIN mutation_event ON mutation.MUTATION_EVENT_ID = mutation_event.MUTATION_EVENT_ID
WHERE mutation_event.ENTREZ_GENE_ID = #{entrezGeneId}
AND mutation_event.PROTEIN_POS_START >= #{proteinPosStart}
AND mutation_event.PROTEIN_POS_END  <=  #{proteinPosEnd}
